mapper.select:
select mao.id , mao.brush_person_id brushPersonId , mao.tb_order_id tbOrderId , mao.order_time orderTime , mao.order_state orderState , mao.seed_money seedMoney , mao.hire_money hireMoney , mao.way_bill_money wayBillMoney , mao.way_bill_code wayBillCode , mao.way_bill_name wayBillName , mo.nick_name brushPersonName , mp.title productName , mp.pic_url productPicUrl , mp.code productId
from mall_add_order mao left join mall_oper mo on mao.brush_person_id = mo.id left join mall_product mp on mao.product_id = mp.code
where 1=1
and brush_person_id = #{mallAddOrderPageDto.brushId}
and tb_order_id = #{mallAddOrderPageDto.tbOrderId}
and order_state = #{mallAddOrderPageDto.orderstate}
and create_time >= #{mallAddOrderPageDto.createTimeStart}
and create_time <= #{mallAddOrderPageDto.createTimeEnd}
order by mao.order_time desc, mao.order_state asc
